import React, { useState } from "react";
import { Link } from "react-router-dom";
import { FaSearch, FaBars, FaTimes } from "react-icons/fa";
import logo from "../assets/logo.png";

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false); // Mobile menu
  const [searchOpen, setSearchOpen] = useState(false); // Search input
  const [query, setQuery] = useState("");

  const links = [
    { name: "Home", path: "/" },
    { name: "About", path: "/about" },
    { name: "Purpose", path: "/purpose" },
    { name: "Vision", path: "/vision" },
    { name: "Domains", path: "/domains" },
    { name: "Team", path: "/team" },
    { name: "Careers", path: "/careers" },
    { name: "Contact", path: "/contact" },
  ];

  const handleSearchSubmit = (e) => {
    e.preventDefault();
    // For now, just log the search query
    console.log("Searching for:", query);
    setQuery("");
    setSearchOpen(false);
  };

  return (
    <nav className="fixed top-0 left-0 w-full bg-white shadow-md z-50">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between h-16 items-center">

          {/* Logo */}
          <Link to="/" className="flex items-center space-x-2">
            <img src={logo} alt="Godemar's Empire Logo" className="h-10 w-10 object-contain"/>
            <span className="text-2xl font-bold text-gray-900">Godemar’s Empire</span>
          </Link>

          {/* Desktop Links */}
          <div className="hidden md:flex space-x-6 items-center">

            {links.map((link, index) => (
              <Link
                key={index}
                to={link.path}
                className="text-gray-700 hover:text-blue-600"
              >
                {link.name}
              </Link>
            ))}

            {/* Search Icon */}
            <div className="relative">
              <button
                onClick={() => setSearchOpen(!searchOpen)}
                className="p-2 rounded-full hover:bg-gray-200"
              >
                <FaSearch className="text-gray-700"/>
              </button>

              {searchOpen && (
                <form
                  onSubmit={handleSearchSubmit}
                  className="absolute right-0 top-12 bg-white shadow-md rounded-md flex items-center px-2 py-1 space-x-2 w-64"
                >
                  <input
                    type="text"
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder="Search..."
                    className="w-full px-2 py-1 border border-gray-300 rounded focus:outline-none focus:ring-2 focus:ring-blue-500"
                  />
                  <button type="submit" className="text-blue-600 font-bold">Go</button>
                </form>
              )}
            </div>
          </div>

          {/* Mobile Hamburger */}
          <div className="md:hidden flex items-center space-x-2">

            {/* Mobile Search */}
            <button
              onClick={() => setSearchOpen(!searchOpen)}
              className="p-2 rounded-full hover:bg-gray-200"
            >
              <FaSearch className="text-gray-700"/>
            </button>

            <button
              onClick={() => setIsOpen(!isOpen)}
              className="p-2 rounded-md hover:bg-gray-200"
            >
              {isOpen ? <FaTimes size={24}/> : <FaBars size={24}/>}
            </button>
          </div>

        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-white shadow-lg">
          <div className="flex flex-col px-4 py-4 space-y-2">
            {links.map((link, index) => (
              <Link
                key={index}
                to={link.path}
                onClick={() => setIsOpen(false)}
                className="text-gray-700 hover:text-blue-600"
              >
                {link.name}
              </Link>
            ))}

            {/* Mobile Search Input */}
            {searchOpen && (
              <form
                onSubmit={handleSearchSubmit}
                className="flex items-center space-x-2 mt-2 px-2 py-1 border border-gray-300 rounded-md"
              >
                <input
                  type="text"
                  value={query}
                  onChange={(e) => setQuery(e.target.value)}
                  placeholder="Search..."
                  className="w-full px-2 py-1 focus:outline-none focus:ring-2 focus:ring-blue-500 rounded-md"
                />
                <button type="submit" className="text-blue-600 font-bold">Go</button>
              </form>
            )}
          </div>
        </div>
      )}
    </nav>
  );
};

export default Navbar;
